        for d in result['details'][:3]:
            facts.append(f\"员工{d['employee_id']} {d['month']}: 合计{d['total_amount']}元, 标准300元, 超标{d['excess']}元, 涉及{d['record_ids']}等\")
        if len(result['details']) > 3:
            facts.append(f\"...共{len(result['details'])}个超标组\")
